+    #[cfg(feature = "sql-sqlite")]
+    #[test]
+    fn sql_inspector_reflect_all_tables_empty_db() {
+        let conn = make_sql_test_conn();
+        let inspector = SqlInspector::new(&conn);
+        let bundles = inspector.reflect_all_tables(None).unwrap();
